judgeConfig.referenceSolution:
(function() {
           const minInput = document.getElementById('minInput');
           const maxInput = document.getElementById('maxInput');
           const rangeInput = document.getElementById('rangeInput');
           const error = document.getElementById('error');
           const label = document.getElementById('rangeLabel');

           minInput.addEventListener('input', () => {
               rangeInput.min = minInput.value;
               label.textContent = `Range: ${minInput.value} - ${maxInput.value}`;
           });

           maxInput.addEventListener('input', () => {
               rangeInput.max = maxInput.value;
               label.textContent = `Range: ${minInput.value} - ${maxInput.value}`;
           });

           rangeInput.addEventListener('input', () => {
               const rangeValue = parseInt(rangeInput.value);
               const minRange = parseInt(minInput.value);
               const maxRange = parseInt(maxInput.value);
               if (rangeValue < minRange || rangeValue > maxRange) {
                   error.textContent = 'Invalid range';
               } else {
                   error.style.display = 'none';
               }
           });

           const updateLabel = () => {
               label.textContent = `Range: ${minInput.value} - ${maxInput.value}`;
           };

           minInput.addEventListener('input', updateLabel);
           maxInput.addEventListener('input', updateLabel);
           })();
